//! Spec-compliance tests: Indentation precedence and lineRule defaults.
//!
//! ECMA-376 §17.3.1.12 (indentation): "The firstLine and hanging attributes
//! are mutually exclusive, if both are specified, then the firstLine value is
//! ignored." — meaning hanging wins.
//!
//! ECMA-376 §17.3.1.33 (spacing): "If this attribute [lineRule] is omitted,
//! then it shall be assumed to be of a value auto if a line attribute value is
//! present."
//!
//! Fixtures generated by `testdata/spec-compliance/spacing-indentation/create_docs.py`.

use stemma::LineSpacingRule;

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/spacing-indentation";

// ── firstLine/hanging precedence ────────────────────────────────────────

/// ECMA-376 §17.3.1.12: When a *paragraph style* defines ind with both
/// `hanging="360"` and `firstLine="720"`, hanging wins. Verifies that the
/// style parser correctly gives hanging precedence over firstLine.
#[test]

fn spec_hanging_wins_over_firstline_in_style() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "hanging-wins-style");
    let paras = common::all_paragraphs(&doc);

    let p = paras
        .iter()
        .find(|p| p.style_id.as_deref() == Some("HangingWins"))
        .expect(
            "should find a paragraph with style_id='HangingWins'. \
             The fixture applies this style but it may not have survived import.",
        );

    let indent = p.indent.as_ref().expect(
        "paragraph with HangingWins style should have indentation resolved from style, \
         but indent is None",
    );

    // §17.3.1.12: hanging wins over firstLine when both are present.
    // hanging=360 → effective_first_line_twips = -360
    assert_eq!(
        indent.effective_first_line_twips,
        Some(-360),
        "ECMA-376 §17.3.1.12: hanging should win over firstLine in style. \
         Expected effective_first_line_twips = -360 (hanging=360), \
         got {:?}. The style parser likely checks firstLine before hanging.",
        indent.effective_first_line_twips
    );
}

/// ECMA-376 §17.3.1.12: When a *numbering level* defines ind with both
/// `hanging="360"` and `firstLine="720"`, hanging wins. Verifies that the
/// numbering parser correctly gives hanging precedence over firstLine.
#[test]

fn spec_hanging_wins_over_firstline_in_numbering() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "hanging-wins-numbering");
    let paras = common::all_paragraphs(&doc);

    // Find the numbered paragraph (it should have numbering info or at least
    // inherit indentation from the numbering level).
    let p = paras
        .iter()
        .find(|p| {
            p.indent
                .as_ref()
                .is_some_and(|i| i.effective_first_line_twips.is_some())
        })
        .expect(
            "should find a paragraph with indentation from numbering. \
             The fixture uses numId=100 ilvl=0 with both hanging and firstLine.",
        );

    let indent = p.indent.as_ref().unwrap();

    // §17.3.1.12: hanging wins over firstLine when both are present.
    assert_eq!(
        indent.effective_first_line_twips,
        Some(-360),
        "ECMA-376 §17.3.1.12: hanging should win over firstLine in numbering level. \
         Expected effective_first_line_twips = -360 (hanging=360), \
         got {:?}. The numbering parser likely checks firstLine before hanging.",
        indent.effective_first_line_twips
    );
}

